"use strict";(self.webpackChunkmy_blog=self.webpackChunkmy_blog||[]).push([[34031],{66262:(n,s)=>{s.A=(n,s)=>{const e=n.__vccOpts||n;for(const[n,a]of s)e[n]=a;return e}},92463:(n,s,e)=>{e.r(s),e.d(s,{comp:()=>d,data:()=>v});var a=e(20641);const i=e.p+"assets/img/Ciqc1F9R3QOAbbKRAAD4lAEEjtg767.f923aea2.png",l=e.p+"assets/img/Ciqc1F9R35eARBOdAAEUxDl6DGE227.eb4430bb.png",p=e.p+"assets/img/CgqCHl9R34eAEosNAAEZMNHAB1c561.cae1fbc0.png",r=e.p+"assets/img/Ciqc1F9R3WuAd1UPAAA82c309GI280.4f8dc631.png",c=e.p+"assets/img/Ciqc1F9R3YiAXV8hAAAtXArd3J0997.8cdeb62e.png",t={},d=(0,e(66262).A)(t,[["render",function(n,s){return(0,a.uX)(),(0,a.CE)("div",null,s[0]||(s[0]=[(0,a.Fv)('<h1 id="_12-简易版-rpc-框架实现-下" tabindex="-1"><a class="header-anchor" href="#_12-简易版-rpc-框架实现-下"><span>12 简易版 RPC 框架实现（下）</span></a></h1><p>在上一课时中，我们介绍了整个简易 RPC 框架项目的结构和工作原理，并且介绍了简易 RPC 框架底层的协议结构、序列化/反序列化实现、压缩实现以及编解码器的具体实现。本课时我们将继续自底向上，介绍简易 RPC 框架的剩余部分实现。</p><h3 id="transport-相关实现" tabindex="-1"><a class="header-anchor" href="#transport-相关实现"><span>transport 相关实现</span></a></h3><p>正如前文介绍 Netty 线程模型的时候提到，我们不能在 Netty 的 I/O 线程中执行耗时的业务逻辑。在 Demo RPC 框架的 Server 端接收到请求时，首先会通过上面介绍的 DemoRpcDecoder 反序列化得到请求消息，之后我们会通过一个自定义的 ChannelHandler（DemoRpcServerHandler）将请求提交给业务线程池进行处理。</p><p>在 Demo RPC 框架的 Client 端接收到响应消息的时候，也是先通过 DemoRpcDecoder 反序列化得到响应消息，之后通过一个自定义的 ChannelHandler（DemoRpcClientHandler）将响应返回给上层业务。</p><p>DemoRpcServerHandler 和 DemoRpcClientHandler 都继承自 SimpleChannelInboundHandler，如下图所示：</p><figure><img src="'+i+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>DemoRpcClientHandler 和 DemoRpcServerHandler 的继承关系图</p><p>下面我们就来看一下这两个自定义的 ChannelHandler 实现：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class DemoRpcServerHandler extends </span></span>\n<span class="line"><span>      SimpleChannelInboundHandler&lt;Message&lt;Request&gt;&gt; {</span></span>\n<span class="line"><span>    // 业务线程池</span></span>\n<span class="line"><span>    static Executor executor = Executors.newCachedThreadPool();</span></span>\n<span class="line"><span>    protected void channelRead0(final ChannelHandlerContext ctx, </span></span>\n<span class="line"><span>          Message&lt;Request&gt; message) throws Exception {</span></span>\n<span class="line"><span>        byte extraInfo = message.getHeader().getExtraInfo();</span></span>\n<span class="line"><span>        if (Constants.isHeartBeat(extraInfo)) { // 心跳消息，直接返回即可</span></span>\n<span class="line"><span>            channelHandlerContext.writeAndFlush(message);</span></span>\n<span class="line"><span>            return;</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        // 非心跳消息，直接封装成Runnable提交到业务线程</span></span>\n<span class="line"><span>        executor.execute(new InvokeRunnable(message, cxt));</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span>\n<span class="line"><span>public class DemoRpcClientHandler extends </span></span>\n<span class="line"><span>      SimpleChannelInboundHandler&lt;Message&lt;Response&gt;&gt; {</span></span>\n<span class="line"><span>    protected void channelRead0(ChannelHandlerContext ctx, </span></span>\n<span class="line"><span>        Message&lt;Response&gt; message) throws Exception {</span></span>\n<span class="line"><span>        NettyResponseFuture responseFuture = </span></span>\n<span class="line"><span>              Connection.IN_FLIGHT_REQUEST_MAP</span></span>\n<span class="line"><span>                  .remove(message.getHeader().getMessageId());</span></span>\n<span class="line"><span>        Response response = message.getContent();</span></span>\n<span class="line"><span>        // 心跳消息特殊处理</span></span>\n<span class="line"><span>        if (response == null &amp;&amp; Constants.isHeartBeat(</span></span>\n<span class="line"><span>                  message.getHeader().getExtraInfo())) {</span></span>\n<span class="line"><span>            response = new Response();</span></span>\n<span class="line"><span>            response.setCode(Constants.HEARTBEAT_CODE);</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        responseFuture.getPromise().setSuccess(response);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意，这里有两个点需要特别说明一下。一个点是 Server 端的 InvokeRunnable，在这个 Runnable 任务中会根据请求的 serviceName、methodName 以及参数信息，调用相应的方法：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>class InvokeRunnable implements Runnable {</span></span>\n<span class="line"><span>    private ChannelHandlerContext ctx;</span></span>\n<span class="line"><span>    private Message&lt;Request&gt; message;</span></span>\n<span class="line"><span>    public void run() {</span></span>\n<span class="line"><span>        Response response = new Response();</span></span>\n<span class="line"><span>        Object result = null;</span></span>\n<span class="line"><span>        try {</span></span>\n<span class="line"><span>            Request request = message.getContent();</span></span>\n<span class="line"><span>            String serviceName = request.getServiceName();</span></span>\n<span class="line"><span>            // 这里提供BeanManager对所有业务Bean进行管理，其底层在内存中维护了</span></span>\n<span class="line"><span>            // 一个业务Bean实例的集合。感兴趣的同学可以尝试接入Spring等容器管</span></span>\n<span class="line"><span>            // 理业务Bean</span></span>\n<span class="line"><span>            Object bean = BeanManager.getBean(serviceName);</span></span>\n<span class="line"><span>            // 下面通过反射调用Bean中的相应方法</span></span>\n<span class="line"><span>            Method method = bean.getClass().getMethod(</span></span>\n<span class="line"><span>                request.getMethodName(), request.getArgTypes());</span></span>\n<span class="line"><span>            result = method.invoke(bean, request.getArgs());</span></span>\n<span class="line"><span>        } catch (Exception e) { // 省略异常处理</span></span>\n<span class="line"><span>        } finally {</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        response.setResult(result); // 设置响应结果</span></span>\n<span class="line"><span>        // 将响应消息返回给客户端</span></span>\n<span class="line"><span>        ctx.writeAndFlush(new Message(message.getHeader(), response));</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>另一个点是 Client 端的 Connection，它是用来暂存已发送出去但未得到响应的请求，这样，在响应返回时，就可以查找到相应的请求以及 Future，从而将响应结果返回给上层业务逻辑，具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class Connection implements Closeable {</span></span>\n<span class="line"><span>    private static AtomicLong ID_GENERATOR = new AtomicLong(0);</span></span>\n<span class="line"><span>    public static Map&lt;Long, NettyResponseFuture&lt;Response&gt;&gt; </span></span>\n<span class="line"><span>        IN_FLIGHT_REQUEST_MAP = new ConcurrentHashMap&lt;&gt;();</span></span>\n<span class="line"><span>    private ChannelFuture future;</span></span>\n<span class="line"><span>    private AtomicBoolean isConnected = new AtomicBoolean();</span></span>\n<span class="line"><span>    public Connection(ChannelFuture future, boolean isConnected) {</span></span>\n<span class="line"><span>        this.future = future;</span></span>\n<span class="line"><span>        this.isConnected.set(isConnected);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    public NettyResponseFuture&lt;Response&gt; request(Message&lt;Request&gt; message, long timeOut) {</span></span>\n<span class="line"><span>        // 生成并设置消息ID</span></span>\n<span class="line"><span>        long messageId = ID_GENERATOR.incrementAndGet();</span></span>\n<span class="line"><span>        message.getHeader().setMessageId(messageId);</span></span>\n<span class="line"><span>        // 创建消息关联的Future</span></span>\n<span class="line"><span>        NettyResponseFuture responseFuture = new NettyResponseFuture(System.currentTimeMillis(),</span></span>\n<span class="line"><span>                timeOut, message, future.channel(), new DefaultPromise(new DefaultEventLoop()));</span></span>\n<span class="line"><span>        // 将消息ID和关联的Future记录到IN_FLIGHT_REQUEST_MAP集合中</span></span>\n<span class="line"><span>        IN_FLIGHT_REQUEST_MAP.put(messageId, responseFuture);</span></span>\n<span class="line"><span>        try {</span></span>\n<span class="line"><span>            future.channel().writeAndFlush(message); // 发送请求</span></span>\n<span class="line"><span>        } catch (Exception e) {</span></span>\n<span class="line"><span>            // 发送请求异常时，删除对应的Future</span></span>\n<span class="line"><span>            IN_FLIGHT_REQUEST_MAP.remove(messageId);</span></span>\n<span class="line"><span>            throw e;</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        return responseFuture;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    // 省略getter/setter以及close()方法</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>我们可以看到，Connection 中没有定时清理 IN_FLIGHT_REQUEST_MAP 集合的操作，在无法正常获取响应的时候，就会导致 IN_FLIGHT_REQUEST_MAP 不断膨胀，最终 OOM。你也可以添加一个时间轮定时器，定时清理过期的请求消息，这里我们就不再展开讲述了。</p><p>完成自定义 ChannelHandler 的编写之后，我们需要再定义两个类—— DemoRpcClient 和 DemoRpcServer，分别作为 Client 和 Server 的启动入口。<strong>DemoRpcClient 的实现如下：</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class DemoRpcClient implements Closeable {</span></span>\n<span class="line"><span>    protected Bootstrap clientBootstrap;</span></span>\n<span class="line"><span>    protected EventLoopGroup group;</span></span>\n<span class="line"><span>    private String host;</span></span>\n<span class="line"><span>    private int port;</span></span>\n<span class="line"><span>    public DemoRpcClient(String host, int port) throws Exception {</span></span>\n<span class="line"><span>        this.host = host;</span></span>\n<span class="line"><span>        this.port = port;</span></span>\n<span class="line"><span>        clientBootstrap = new Bootstrap();</span></span>\n<span class="line"><span>        // 创建并配置客户端Bootstrap</span></span>\n<span class="line"><span>        group = NettyEventLoopFactory.eventLoopGroup(</span></span>\n<span class="line"><span>            Constants.DEFAULT_IO_THREADS, &quot;NettyClientWorker&quot;);</span></span>\n<span class="line"><span>        clientBootstrap.group(group)</span></span>\n<span class="line"><span>                .option(ChannelOption.TCP_NODELAY, true)</span></span>\n<span class="line"><span>                .option(ChannelOption.SO_KEEPALIVE, true)</span></span>\n<span class="line"><span>                .channel(NioSocketChannel.class)</span></span>\n<span class="line"><span>                // 指定ChannelHandler的顺序</span></span>\n<span class="line"><span>                .handler(new ChannelInitializer&lt;SocketChannel&gt;() {</span></span>\n<span class="line"><span>                    protected void initChannel(SocketChannel ch) {</span></span>\n<span class="line"><span>                        ch.pipeline().addLast(&quot;demo-rpc-encoder&quot;, </span></span>\n<span class="line"><span>                            new DemoRpcEncoder());</span></span>\n<span class="line"><span>                        ch.pipeline().addLast(&quot;demo-rpc-decoder&quot;, </span></span>\n<span class="line"><span>                            new DemoRpcDecoder());</span></span>\n<span class="line"><span>                        ch.pipeline().addLast(&quot;client-handler&quot;, </span></span>\n<span class="line"><span>                            new DemoRpcClientHandler());</span></span>\n<span class="line"><span>                    }</span></span>\n<span class="line"><span>                });</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    public ChannelFuture connect() { // 连接指定的地址和端口</span></span>\n<span class="line"><span>        ChannelFuture connect = clientBootstrap.connect(host, port);</span></span>\n<span class="line"><span>        connect.awaitUninterruptibly();</span></span>\n<span class="line"><span>        return connect;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    public void close() {</span></span>\n<span class="line"><span>        group.shutdownGracefully();</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过 DemoRpcClient 的代码我们可以看到其 ChannelHandler 的执行顺序如下：</p><figure><img src="'+l+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>客户端 ChannelHandler 结构图</p><p>另外，在创建EventLoopGroup时并没有直接使用NioEventLoopGroup，而是在 NettyEventLoopFactory 中根据当前操作系统进行选择，对于 Linux 系统，会使用 EpollEventLoopGroup，其他系统则使用 NioEventLoopGroup。</p><p>接下来我们再看<strong>DemoRpcServer 的具体实现</strong>：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class DemoRpcServer {</span></span>\n<span class="line"><span>    private EventLoopGroup bossGroup;</span></span>\n<span class="line"><span>    private EventLoopGroup workerGroup;</span></span>\n<span class="line"><span>    private ServerBootstrap serverBootstrap;</span></span>\n<span class="line"><span>    private Channel channel;</span></span>\n<span class="line"><span>    protected int port;</span></span>\n<span class="line"><span>    public DemoRpcServer(int port) throws InterruptedException {</span></span>\n<span class="line"><span>        this.port = port;</span></span>\n<span class="line"><span>        // 创建boss和worker两个EventLoopGroup，注意一些小细节， </span></span>\n<span class="line"><span>        // workerGroup 是按照中的线程数是按照 CPU 核数计算得到的，</span></span>\n<span class="line"><span>        bossGroup = NettyEventLoopFactory.eventLoopGroup(1, &quot;boos&quot;);</span></span>\n<span class="line"><span>        workerGroup = NettyEventLoopFactory.eventLoopGroup( </span></span>\n<span class="line"><span>            Math.min(Runtime.getRuntime().availableProcessors() + 1,</span></span>\n<span class="line"><span>                 32), &quot;worker&quot;);</span></span>\n<span class="line"><span>        serverBootstrap = new ServerBootstrap().group(bossGroup, </span></span>\n<span class="line"><span>                    workerGroup).channel(NioServerSocketChannel.class)</span></span>\n<span class="line"><span>                .option(ChannelOption.SO_REUSEADDR, Boolean.TRUE)</span></span>\n<span class="line"><span>                .childOption(ChannelOption.TCP_NODELAY, Boolean.TRUE)</span></span>\n<span class="line"><span>                .handler(new LoggingHandler(LogLevel.INFO))</span></span>\n<span class="line"><span>                .childHandler(new ChannelInitializer&lt;SocketChannel&gt;()</span></span>\n<span class="line"><span>                  { // 指定每个Channel上注册的ChannelHandler以及顺序</span></span>\n<span class="line"><span>                    protected void initChannel(SocketChannel ch) {</span></span>\n<span class="line"><span>                       ch.pipeline().addLast(&quot;demp-rpc-decoder&quot;, </span></span>\n<span class="line"><span>                            new DemoRpcDecoder());</span></span>\n<span class="line"><span>                       ch.pipeline().addLast(&quot;demo-rpc-encoder&quot;, </span></span>\n<span class="line"><span>                            new DemoRpcEncoder());</span></span>\n<span class="line"><span>                       ch.pipeline().addLast(&quot;server-handler&quot;, </span></span>\n<span class="line"><span>                            new DemoRpcServerHandler());</span></span>\n<span class="line"><span>                     }</span></span>\n<span class="line"><span>         });</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    public ChannelFuture start() throws InterruptedException {</span></span>\n<span class="line"><span>        ChannelFuture channelFuture = serverBootstrap.bind(port);</span></span>\n<span class="line"><span>        channel = channelFuture.channel();</span></span>\n<span class="line"><span>        channel.closeFuture();</span></span>\n<span class="line"><span>        return channelFuture;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过对 DemoRpcServer 实现的分析，我们可以知道每个 Channel 上的 ChannelHandler 顺序如下：</p><figure><img src="'+p+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>服务端 ChannelHandler 结构图</p><h3 id="registry-相关实现" tabindex="-1"><a class="header-anchor" href="#registry-相关实现"><span>registry 相关实现</span></a></h3><p>介绍完客户端和服务端的通信之后，我们再来看简易 RPC 框架的另一个基础能力——服务注册与服务发现能力，对应 demo-rpc 项目源码中的 registry 包。</p><p>registry 包主要是依赖 Apache Curator 实现了一个简易版本的 ZooKeeper 客户端，并基于 ZooKeeper 实现了注册中心最基本的两个功能：Provider 注册以及 Consumer 订阅。</p><p>这里我们先定义一个 Registry 接口，其中提供了注册以及查询服务实例的方法，如下图所示：</p><figure><img src="'+r+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>ZooKeeperRegistry 是基于 curator-x-discovery 对 Registry 接口的实现类型，其中封装了之前课时介绍的 ServiceDiscovery，并在其上添加了 ServiceCache 缓存提高查询效率。ZooKeeperRegistry 的具体实现如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class ZookeeperRegistry&lt;T&gt; implements Registry&lt;T&gt; {</span></span>\n<span class="line"><span>    private InstanceSerializer serializer = </span></span>\n<span class="line"><span>          new JsonInstanceSerializer&lt;&gt;(ServerInfo.class);</span></span>\n<span class="line"><span>    private ServiceDiscovery&lt;T&gt; serviceDiscovery;</span></span>\n<span class="line"><span>    private ServiceCache&lt;T&gt; serviceCache;</span></span>\n<span class="line"><span>    private String address = &quot;localhost:2181&quot;;</span></span>\n<span class="line"><span>    public void start() throws Exception {</span></span>\n<span class="line"><span>        String root = &quot;/demo/rpc&quot;;</span></span>\n<span class="line"><span>        // 初始化CuratorFramework</span></span>\n<span class="line"><span>        CuratorFramework client = CuratorFrameworkFactory</span></span>\n<span class="line"><span>            .newClient(address, new ExponentialBackoffRetry(1000, 3));</span></span>\n<span class="line"><span>        client.start(); // 启动Curator客户端</span></span>\n<span class="line"><span>        client.blockUntilConnected();  // 阻塞当前线程，等待连接成</span></span>\n<span class="line"><span>        client.createContainers(root);</span></span>\n<span class="line"><span>        // 初始化ServiceDiscovery</span></span>\n<span class="line"><span>        serviceDiscovery = ServiceDiscoveryBuilder</span></span>\n<span class="line"><span>                .builder(ServerInfo.class)</span></span>\n<span class="line"><span>                .client(client).basePath(root)</span></span>\n<span class="line"><span>                .serializer(serializer)</span></span>\n<span class="line"><span>                .build();</span></span>\n<span class="line"><span>        serviceDiscovery.start(); // 启动ServiceDiscovery</span></span>\n<span class="line"><span>        // 创建ServiceCache，监Zookeeper相应节点的变化，也方便后续的读取</span></span>\n<span class="line"><span>        serviceCache = serviceDiscovery.serviceCacheBuilder()</span></span>\n<span class="line"><span>                .name(root)</span></span>\n<span class="line"><span>                .build();</span></span>\n<span class="line"><span>        serviceCache.start(); // 启动ServiceCache</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span>    public void registerService(ServiceInstance&lt;T&gt; service)</span></span>\n<span class="line"><span>             throws Exception {</span></span>\n<span class="line"><span>        serviceDiscovery.registerService(service);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span>    public void unregisterService(ServiceInstance service) </span></span>\n<span class="line"><span>          throws Exception {</span></span>\n<span class="line"><span>        serviceDiscovery.unregisterService(service);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span>    public List&lt;ServiceInstance&lt;T&gt;&gt; queryForInstances(</span></span>\n<span class="line"><span>            String name) throws Exception {</span></span>\n<span class="line"><span>        // 直接根据name进行过滤ServiceCache中的缓存数据 </span></span>\n<span class="line"><span>        return serviceCache.getInstances().stream()</span></span>\n<span class="line"><span>            .filter(s -&gt; s.getName().equals(name))</span></span>\n<span class="line"><span>                .collect(Collectors.toList());</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过对 ZooKeeperRegistry的分析可以得知，它是基于 Curator 中的 ServiceDiscovery 组件与 ZooKeeper 进行交互的，并且对 Registry 接口的实现也是通过直接调用 ServiceDiscovery 的相关方法实现的。在查询时，直接读取 ServiceCache 中的缓存数据，ServiceCache 底层在本地维护了一个 ConcurrentHashMap 缓存，通过 PathChildrenCache 监听 ZooKeeper 中各个子节点的变化，同步更新本地缓存。这里我们简单看一下 ServiceCache 的核心实现：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class ServiceCacheImpl&lt;T&gt; implements ServiceCache&lt;T&gt;, </span></span>\n<span class="line"><span>  PathChildrenCacheListener{//实现PathChildrenCacheListener接口</span></span>\n<span class="line"><span>    // 关联的ServiceDiscovery实例</span></span>\n<span class="line"><span>    private final ServiceDiscoveryImpl&lt;T&gt;  discovery;</span></span>\n<span class="line"><span>    // 底层的PathChildrenCache，用于监听子节点的变化</span></span>\n<span class="line"><span>    private final PathChildrenCache cache; </span></span>\n<span class="line"><span>    // 本地缓存</span></span>\n<span class="line"><span>    private final ConcurrentMap&lt;String, ServiceInstance&lt;T&gt;&gt; instances </span></span>\n<span class="line"><span>      = Maps.newConcurrentMap();</span></span>\n<span class="line"><span>    public List&lt;ServiceInstance&lt;T&gt;&gt; getInstances(){ // 返回本地缓存内容</span></span>\n<span class="line"><span>        return Lists.newArrayList(instances.values());</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    public void childEvent(CuratorFramework client, </span></span>\n<span class="line"><span>          PathChildrenCacheEvent event) throws Exception{</span></span>\n<span class="line"><span>        switch(event.getType()){</span></span>\n<span class="line"><span>            case CHILD_ADDED:</span></span>\n<span class="line"><span>            case CHILD_UPDATED:{</span></span>\n<span class="line"><span>                addInstance(event.getData(), false); // 更新本地缓存</span></span>\n<span class="line"><span>                notifyListeners = true;</span></span>\n<span class="line"><span>                break;</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>            case CHILD_REMOVED:{ // 更新本地缓存</span></span>\n<span class="line"><span>                instances.remove(instanceIdFromData(event.getData()));</span></span>\n<span class="line"><span>                notifyListeners = true;</span></span>\n<span class="line"><span>                break;</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        ... // 通知ServiceCache上注册的监听器</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="proxy-相关实现" tabindex="-1"><a class="header-anchor" href="#proxy-相关实现"><span>proxy 相关实现</span></a></h3><p>在简易版 Demo RPC 框架中，Proxy 主要是为 Client 端创建一个代理，帮助客户端程序屏蔽底层的网络操作以及与注册中心之间的交互。</p><p>简易版 Demo RPC 使用 JDK 动态代理的方式生成代理，这里需要编写一个 InvocationHandler 接口的实现，即下面的 DemoRpcProxy。其中有两个核心方法：一个是 newInstance() 方法，用于生成代理对象；另一个是 invoke() 方法，当调用目标对象的时候，会执行 invoke() 方法中的代理逻辑。</p><p>下面是 DemoRpcProxy 的具体实现：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class DemoRpcProxy implements InvocationHandler {</span></span>\n<span class="line"><span>    // 需要代理的服务(接口)名称</span></span>\n<span class="line"><span>    private String serviceName;</span></span>\n<span class="line"><span>    // 用于与Zookeeper交互，其中自带缓存</span></span>\n<span class="line"><span>    private Registry&lt;ServerInfo&gt; registry;</span></span>\n<span class="line"><span>    public DemoRpcProxy(String serviceName, Registry&lt;ServerInfo&gt; </span></span>\n<span class="line"><span>            registry) throws Exception { // 初始化上述两个字段</span></span>\n<span class="line"><span>        this.serviceName = serviceName;</span></span>\n<span class="line"><span>        this.registry = registry;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    public static &lt;T&gt; T newInstance(Class&lt;T&gt; clazz, </span></span>\n<span class="line"><span>        Registry&lt;ServerInfo&gt; registry) throws Exception {</span></span>\n<span class="line"><span>        // 创建代理对象</span></span>\n<span class="line"><span>        return (T) Proxy.newProxyInstance(Thread.currentThread()</span></span>\n<span class="line"><span>            .getContextClassLoader(), new Class[]{clazz},</span></span>\n<span class="line"><span>                new DemoRpcProxy(clazz.getName(), registry));</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span>    public Object invoke(Object proxy, Method method, Object[] args)</span></span>\n<span class="line"><span>           throws Throwable {</span></span>\n<span class="line"><span>        // 从Zookeeper缓存中获取可用的Server地址,并随机从中选择一个</span></span>\n<span class="line"><span>        List&lt;ServiceInstance&lt;ServerInfo&gt;&gt; serviceInstances = </span></span>\n<span class="line"><span>              registry.queryForInstances(serviceName);</span></span>\n<span class="line"><span>        ServiceInstance&lt;ServerInfo&gt; serviceInstance = serviceInstances</span></span>\n<span class="line"><span>            .get(ThreadLocalRandom.current()</span></span>\n<span class="line"><span>                .nextInt(serviceInstances.size()));</span></span>\n<span class="line"><span>        // 创建请求消息，然后调用remoteCall()方法请求上面选定的Server端</span></span>\n<span class="line"><span>        String methodName = method.getName();</span></span>\n<span class="line"><span>        Header header =new Header(MAGIC, VERSION_1...);</span></span>\n<span class="line"><span>        Message&lt;Request&gt; message = new Message(header, </span></span>\n<span class="line"><span>            new Request(serviceName, methodName, args));</span></span>\n<span class="line"><span>        return remoteCall(serviceInstance.getPayload(), message);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>    protected Object remoteCall(ServerInfo serverInfo, </span></span>\n<span class="line"><span>            Message message) throws Exception {</span></span>\n<span class="line"><span>        if (serverInfo == null) {</span></span>\n<span class="line"><span>            throw new RuntimeException(&quot;get available server error&quot;);</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>        // 创建DemoRpcClient连接指定的Server端</span></span>\n<span class="line"><span>        DemoRpcClient demoRpcClient = new DemoRpcClient(</span></span>\n<span class="line"><span>              serverInfo.getHost(), serverInfo.getPort());</span></span>\n<span class="line"><span>        ChannelFuture channelFuture = demoRpcClient.connect()</span></span>\n<span class="line"><span>              .awaitUninterruptibly();</span></span>\n<span class="line"><span>        // 创建对应的Connection对象，并发送请求</span></span>\n<span class="line"><span>        Connection connection = new Connection(channelFuture, true);</span></span>\n<span class="line"><span>        NettyResponseFuture responseFuture =</span></span>\n<span class="line"><span>             connection.request(message, Constants.DEFAULT_TIMEOUT);</span></span>\n<span class="line"><span>        // 等待请求对应的响应</span></span>\n<span class="line"><span>        return responseFuture.getPromise().get(</span></span>\n<span class="line"><span>            Constants.DEFAULT_TIMEOUT, TimeUnit.MILLISECONDS);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>从 DemoRpcProxy 的实现中我们可以看到，它依赖了 ServiceInstanceCache 获取ZooKeeper 中注册的 Server 端地址，同时依赖了 DemoRpcClient 与Server 端进行通信，上层调用方拿到这个代理对象后，就可以像调用本地方法一样进行调用，而不再关心底层网络通信和服务发现的细节。当然，这个简易版 DemoRpcProxy 的实现还有很多可以优化的地方，例如：</p><ul><li>缓存 DemoRpcClient 客户端对象以及相应的 Connection 对象，不必每次进行创建。</li><li>可以添加失败重试机制，在请求出现超时的时候，进行重试。</li><li>可以添加更加复杂和灵活的负载均衡机制，例如，根据 Hash 值散列进行负载均衡、根据节点 load 情况进行负载均衡等。</li></ul><p>你若感兴趣的话可以尝试进行扩展，以实现一个更加完善的代理层。</p><h3 id="使用方接入" tabindex="-1"><a class="header-anchor" href="#使用方接入"><span>使用方接入</span></a></h3><p>介绍完 Demo RPC 的核心实现之后，下面我们讲解下Demo RPC 框架的使用方式。这里涉及Consumer、DemoServiceImp、Provider三个类以及 DemoService 业务接口。</p><figure><img src="'+c+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>使用接入的相关类</p><p>首先，我们定义<strong>DemoService 接口</strong>作为业务 Server 接口，具体定义如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public interface DemoService {</span></span>\n<span class="line"><span>    String sayHello(String param);</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>DemoServiceImpl</strong>对 DemoService 接口的实现也非常简单，如下所示，将参数做简单修改后返回：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class DemoServiceImpl implements DemoService {</span></span>\n<span class="line"><span>    public String sayHello(String param) {</span></span>\n<span class="line"><span>        return &quot;hello:&quot; + param;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>了解完相应的业务接口和实现之后，我们再来看<strong>Provider</strong>的实现，它的角色类似于 Dubbo 中的 Provider，其会创建 DemoServiceImpl 这个业务 Bean 并将自身的地址信息暴露出去，如下所示：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class Provider {</span></span>\n<span class="line"><span>    public static void main(String[] args) throws Exception {</span></span>\n<span class="line"><span>        // 创建DemoServiceImpl，并注册到BeanManager中</span></span>\n<span class="line"><span>        BeanManager.registerBean(&quot;demoService&quot;, </span></span>\n<span class="line"><span>                new DemoServiceImpl());</span></span>\n<span class="line"><span>        // 创建ZookeeperRegistry，并将Provider的地址信息封装成ServerInfo</span></span>\n<span class="line"><span>        // 对象注册到Zookeeper</span></span>\n<span class="line"><span>        ZookeeperRegistry&lt;ServerInfo&gt; discovery = </span></span>\n<span class="line"><span>                new ZookeeperRegistry&lt;&gt;();</span></span>\n<span class="line"><span>        discovery.start();</span></span>\n<span class="line"><span>        ServerInfo serverInfo = new ServerInfo(&quot;127.0.0.1&quot;, 20880);</span></span>\n<span class="line"><span>        discovery.registerService(</span></span>\n<span class="line"><span>             ServiceInstance.&lt;ServerInfo&gt;builder().name(&quot;demoService&quot;)</span></span>\n<span class="line"><span>                .payload(serverInfo).build());</span></span>\n<span class="line"><span>        // 启动DemoRpcServer，等待Client的请求</span></span>\n<span class="line"><span>        DemoRpcServer rpcServer = new DemoRpcServer(20880);</span></span>\n<span class="line"><span>        rpcServer.start();</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>最后是Consumer，它类似于 Dubbo 中的 Consumer，其会订阅 Provider 地址信息，然后根据这些信息选择一个 Provider 建立连接，发送请求并得到响应，这些过程在 Proxy 中都予以了封装，那Consumer 的实现就很简单了，可参考如下示例代码：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>public class Consumer {</span></span>\n<span class="line"><span>    public static void main(String[] args) throws Exception {</span></span>\n<span class="line"><span>        // 创建ZookeeperRegistr对象</span></span>\n<span class="line"><span>        ZookeeperRegistry&lt;ServerInfo&gt; discovery = new ZookeeperRegistry&lt;&gt;();</span></span>\n<span class="line"><span>        // 创建代理对象，通过代理调用远端Server</span></span>\n<span class="line"><span>        DemoService demoService = DemoRpcProxy.newInstance(DemoService.class, discovery);</span></span>\n<span class="line"><span>        // 调用sayHello()方法，并输出结果</span></span>\n<span class="line"><span>        String result = demoService.sayHello(&quot;hello&quot;);</span></span>\n<span class="line"><span>        System.out.println(result);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h3><p>本课时我们首先介绍了简易 RPC 框架中的<strong>transport 包</strong>，它在上一课时介绍的编解码器基础之上，<strong>实现了服务端和客户端的通信能力</strong>。之后讲解了<strong>registry 包</strong>如何实现与 ZooKeeper 的交互，<strong>完善了简易 RPC 框架的服务注册与服务发现的能力</strong>。接下来又分析了<strong>proxy 包</strong>的实现，其中通过 JDK 动态代理的方式，<strong>帮接入方屏蔽了底层网络通信的复杂性</strong>。最后，我们编写了一个简单的 DemoService 业务接口，以及相应的 Provider 和 Consumer 接入简易 RPC 框架。</p><p>在本课时最后，留给你一个小问题：在 transport 中创建 EventLoopGroup 的时候，为什么针对 Linux 系统使用的 EventLoopGroup会有所不同呢？期待你的留言。</p><p>简易版 RPC 框架 Demo 的链接：<a href="https://github.com/xxxlxy2008/demo-prc" target="_blank" rel="noopener noreferrer">https://github.com/xxxlxy2008/demo-prc</a> 。</p>',59)]))}]]),v=JSON.parse('{"path":"/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98-%E5%AE%8C/12%20%20%E7%AE%80%E6%98%93%E7%89%88%20RPC%20%E6%A1%86%E6%9E%B6%E5%AE%9E%E7%8E%B0%EF%BC%88%E4%B8%8B%EF%BC%89.html","title":"12  简易版 RPC 框架实现（下）","lang":"zh-CN","frontmatter":{"description":"12 简易版 RPC 框架实现（下） 在上一课时中，我们介绍了整个简易 RPC 框架项目的结构和工作原理，并且介绍了简易 RPC 框架底层的协议结构、序列化/反序列化实现、压缩实现以及编解码器的具体实现。本课时我们将继续自底向上，介绍简易 RPC 框架的剩余部分实现。 transport 相关实现 正如前文介绍 Netty 线程模型的时候提到，我们不能...","head":[["meta",{"property":"og:url","content":"https://chenmingxing1012.github.io/blog/column/Dubbo%E6%BA%90%E7%A0%81%E8%A7%A3%E8%AF%BB%E4%B8%8E%E5%AE%9E%E6%88%98-%E5%AE%8C/12%20%20%E7%AE%80%E6%98%93%E7%89%88%20RPC%20%E6%A1%86%E6%9E%B6%E5%AE%9E%E7%8E%B0%EF%BC%88%E4%B8%8B%EF%BC%89.html"}],["meta",{"property":"og:site_name","content":"凡人修码传"}],["meta",{"property":"og:title","content":"12  简易版 RPC 框架实现（下）"}],["meta",{"property":"og:description","content":"12 简易版 RPC 框架实现（下） 在上一课时中，我们介绍了整个简易 RPC 框架项目的结构和工作原理，并且介绍了简易 RPC 框架底层的协议结构、序列化/反序列化实现、压缩实现以及编解码器的具体实现。本课时我们将继续自底向上，介绍简易 RPC 框架的剩余部分实现。 transport 相关实现 正如前文介绍 Netty 线程模型的时候提到，我们不能..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-06-05T15:33:29.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-05T15:33:29.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"12  简易版 RPC 框架实现（下）\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-06-05T15:33:29.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"韩跑跑\\",\\"url\\":\\"https://chenmingxing1012.github.io/blog/\\"}]}"]]},"headers":[{"level":3,"title":"transport 相关实现","slug":"transport-相关实现","link":"#transport-相关实现","children":[]},{"level":3,"title":"registry 相关实现","slug":"registry-相关实现","link":"#registry-相关实现","children":[]},{"level":3,"title":"proxy 相关实现","slug":"proxy-相关实现","link":"#proxy-相关实现","children":[]},{"level":3,"title":"使用方接入","slug":"使用方接入","link":"#使用方接入","children":[]},{"level":3,"title":"总结","slug":"总结","link":"#总结","children":[]}],"git":{"createdTime":1780673609000,"updatedTime":1780673609000,"contributors":[{"name":"chenmingxing","email":"1060303243@qq.com","commits":1}]},"readingTime":{"minutes":11.01,"words":3303},"filePathRelative":"column/Dubbo源码解读与实战-完/12  简易版 RPC 框架实现（下）.md","localizedDate":"2026年6月5日","excerpt":"\\n<p>在上一课时中，我们介绍了整个简易 RPC 框架项目的结构和工作原理，并且介绍了简易 RPC 框架底层的协议结构、序列化/反序列化实现、压缩实现以及编解码器的具体实现。本课时我们将继续自底向上，介绍简易 RPC 框架的剩余部分实现。</p>\\n<h3>transport 相关实现</h3>\\n<p>正如前文介绍 Netty 线程模型的时候提到，我们不能在 Netty 的 I/O 线程中执行耗时的业务逻辑。在 Demo RPC 框架的 Server 端接收到请求时，首先会通过上面介绍的 DemoRpcDecoder 反序列化得到请求消息，之后我们会通过一个自定义的 ChannelHandler（DemoRpcServerHandler）将请求提交给业务线程池进行处理。</p>","autoDesc":true}')}}]);